mapper.select:


	1 = 1

		and sdd.dict_type_affiliation = #{dictTypeAffiliation}


		AND sdd.dict_type != 'vehicle_attribute'


		AND sdd.dict_type = #{dictType}


		AND sdd.dict_label like concat('%', #{dictLabel}, '%')


		AND sdd.status = #{status}


		AND sdd.rule_type = #{ruleType}


order by sdd.dict_sort asc

mapper.update:
update sys_dict_data
dict_sort = #{dictSort}, dict_label = #{dictLabel}, dict_value = #{dictValue}, dict_type = #{dictType}, css_class = #{cssClass}, rule = #{rule}, range_rule = #{rangeRule}, key_map = #{keyMap}, value_map = #{valueMap}, is_default = #{isDefault}, status = #{status}, remark = #{remark}, update_by = #{updateBy}, dict_type_affiliation = #{dictTypeAffiliation}, rule_type = #{ruleType}, update_time = sysdate()
where dict_code = #{dictCode}
